import React, { useEffect } from 'react';
import FlexMobileContainer from '../common/flex/flexMobileContainer';
import { DoScroll } from '../../helper/winHelper';
import DegreePhoto from './degree.png';
import WuhanPhoto from './Wuhan.png';
import WuhanUniversityPhoto from './WuhanUniversity.png';
import WuhanUniversityPhoto2 from './WuhanUniversity2.png';
import Styled from 'styled-components';

const StyleImageContainer = Styled.div`
  cursor: pointer;
  width: 200px;
  height: 200px;
  overflow: hidden;
  margin: 30px;
  flex-grow: 0;
  flex-shrink: 0;

  @media (max-width: 768px) {
    display: none;
  }
`;

const StyleImage = Styled.img`
  width: 600px;
  height: 400px;

  @media (max-width: 1024px) {
    width: 80%;
    height: auto;
  }
`;


const Section = (props) => {
  const { backgroundColor, color } = props.style;
  return (
    <div {...props} style={{width: '100%', backgroundColor, color}}>
      <FlexMobileContainer>
        {props.children}
      </FlexMobileContainer>
    </div>
  )
}

const Experience = (props) => {
  useEffect(() => {
    DoScroll();
  }, []);
  
  return (
    <div>
      <Section style={{backgroundColor: props.theme.home.background1, color: props.theme.home.color}}> 
        <div style={{display: 'flex', padding: '40px 0px'}}>
          <StyleImageContainer style={{border: 'solid 1px #626568'}} >
              <img src={DegreePhoto} style={{width: '200px', height: '200px'}} alt="" />
          </StyleImageContainer>
          <div style={{flexGrow: '1', marginLeft: '20px'}}>
            <div style={{display: 'flex', justifyContent: 'space-between', alignItems: 'center'}}>
              <div>
                <div style={{fontSize: '24px', fontWeight: 'bold'}}>Wuhan University, Wuhan, China</div>
                <div style={{fontSize: '18px', fontWeight: 'bold'}}>Doctor of Philosophy</div>
              </div>

            </div>
            <p style={{fontSize: '20px'}}>Major in Geographic Information System</p>
            <StyleImage src={WuhanUniversityPhoto} alt="" />
          </div>
        </div>

      </Section>

      <Section style={{backgroundColor: props.theme.home.background2, color: props.theme.home.color}}> 
        <div style={{display: 'flex', padding: '40px 0px'}}>
          <StyleImageContainer style={{border: 'solid 1px #626568'}} >
              <img src={DegreePhoto} style={{width: '200px', height: '200px'}} alt="" />
          </StyleImageContainer>
          <div style={{flexGrow: '1', marginLeft: '20px'}}>
            <div style={{display: 'flex', justifyContent: 'space-between', alignItems: 'center'}}>
              <div>
                <div style={{fontSize: '24px', fontWeight: 'bold'}}>Institute of Seismology, Wuhan, China</div>
                <div style={{fontSize: '18px', fontWeight: 'bold'}}>Master of Science</div>
              </div>

            </div>
            <p style={{fontSize: '20px'}}>Major in Geographic Information System</p>
            <StyleImage src={WuhanPhoto} alt="" />
          </div>
        </div>

      </Section>

      <Section style={{backgroundColor: props.theme.home.background1, color: props.theme.home.color}}> 
        <div style={{display: 'flex', padding: '40px 0px'}}>
          <StyleImageContainer style={{border: 'solid 1px #626568'}} >
              <img src={DegreePhoto} style={{width: '200px', height: '200px'}} alt="" />
          </StyleImageContainer>
          <div style={{flexGrow: '1', marginLeft: '20px'}}>
            <div style={{display: 'flex', justifyContent: 'space-between', alignItems: 'center'}}>
              <div>
                <div style={{fontSize: '24px', fontWeight: 'bold'}}>Wuhan University, Wuhan, China</div>
                <div style={{fontSize: '18px', fontWeight: 'bold'}}>Bachelor of Engineering</div>
              </div>

            </div>
            <p style={{fontSize: '20px'}}>Major in Geographic Information System</p>
            <StyleImage src={WuhanUniversityPhoto2} alt="" />
          </div>
        </div>

      </Section>


    </div>
  )
}

export default Experience;