import React, { useContext, useEffect } from "react";
import { BrowserRouter as Router, Route } from "react-router-dom";
import ContentTemplate from "./component/contentTemplate/index";
import { AppContext } from './context/appContext';
import { AuthService } from './service/auth';
import Header from './component/headerFooter/index';
import Footer from './component/headerFooter/footer';
import WindowWidth from "./component/common/windowWidth";
import { ThemeProvider } from "styled-components";
import { themes } from "./component/theme/themes"
import { GlobalStyles } from './component/theme/globalStyles';

const AppComponent = (props) => {
  const { CurrentTheme, dispatch } = useContext(AppContext);

  useEffect(() => {
    let userInfo = AuthService.getUserInfo();
    if (userInfo) {
      dispatch({type:'LOGIN', data:userInfo});
    }
    const themeValue = window.localStorage.getItem("MyTheme");
    if (themeValue) {
      dispatch({type: 'SET_THEME', data: themeValue});
    }
  }, [dispatch])

  return (
    <Router>
      <ThemeProvider theme={themes[CurrentTheme]}>
        <GlobalStyles />
        <Header />
          <Route exact path="/" component={ContentTemplate} />
        <Footer />
        <WindowWidth />
      </ThemeProvider>
    </Router>
  );
}

export default AppComponent;

