import React, { useEffect } from 'react';
import FlexLeftRight from '../common/flex/flexLeftRight';
import FlexMobileContainer from '../common/flex/flexMobileContainer';
import { DoScroll } from '../../helper/winHelper';
import LinearProgress from '@material-ui/core/LinearProgress';
import Box from '@material-ui/core/Box';
import { withStyles } from '@material-ui/core/styles';
import FengPhoto from './Feng.png';
import SkillPhoto from './skills.png';
import ProgrammingPhoto from './programming.png';
import HobbyPhoto from './hobby.png';
import Styled from 'styled-components';

const StyledImage = Styled.div`
  width: 200px;
  height: 200px;
  border-radius: 50%;
  overflow: hidden;
  margin: 30px;
  flex-grow: 0;
  flex-shrink: 0;

  @media (max-width: 768px) {
    display: none;
  }
`;

const BorderLinearProgress = withStyles((theme) => ({
  root: {
    height: 20,
  },
  colorPrimary: {
    backgroundColor: '#d8d8d8',
  },
  bar: {
    borderRadius: 0,
    backgroundColor: '#008000',
  },
}))(LinearProgress);


const Section = (props) => {
  const { backgroundColor, color } = props.style;
  return (
    <div {...props} style={{width: '100%', backgroundColor, color}}>
      <FlexMobileContainer>
        {props.children}
      </FlexMobileContainer>
    </div>
  )
}

