import React, { useEffect } from "react";
import { DoScroll } from '../../helper/winHelper';

const ResumeComponent = (props) => {
  useEffect(() => {
    DoScroll();
  }, []);

  return (
    <div style={{display: 'flex', flexDirection: 'column', alignItems: 'center', minHeight: '600px', padding: '40px'}}>
      <h2 style={{margin: '0px', paddingTop: '10px', paddingBottom: '40px'}}>Feng Wang's Resume</h2>

      <div style={{fontSize: '20px', marginBottom: '40px'}}>
        <a href="https://drive.google.com/file/d/1p7FIFEwBth0v0ckENCTHZ3HghsRJDmBr/view?usp=sharing" target="_blank" rel="noopener noreferrer">Resume in PDF format</a>
      </div>

      <div style={{fontSize: '20px'}}>
        <a href="https://drive.google.com/file/d/1u5mkH1pgAXlEs9wUfzHIbW7CcqvqDzqo/view?usp=sharing" target="_blank" rel="noopener noreferrer">Resume in WORD format</a>
      </div>
    </div>
  )
}

export default ResumeComponent;