import React, { useEffect } from "react";
import { DoScroll } from '../../helper/winHelper';
import FlexMobileContainer from '../common/flex/flexMobileContainer';
import Styled from 'styled-components';
import WellflagPhoto from './wellflag.png';
import StockHubPhoto from './StockHub.png';

const Section = (props) => {
  const { backgroundColor, color } = props.style;
  return (
    <div {...props} style={{width: '100%', backgroundColor, color}}>
      <FlexMobileContainer>
        {props.children}
      </FlexMobileContainer>
    </div>
  )
}

const StyledContainer = Styled.div`
  padding: 40px 0px;
  display: flex;
  width: 90%;
  margin: auto;

  @media (max-width: 1248px) {
    flex-direction: ${props => props.reverse ? 'column-reverse' : 'column' };
  }
`;

const StyledLeft = Styled.div`
  flex-grow: 1;
  flex-shrink: 0;
  flex-basis: 100px;
  padding: 20px;
`;

const StyledRight = Styled.div`  
  flex-grow: 1;
  flex-shrink: 0;
  flex-basis: 100px;
  padding: 20px;
`;

const StyledTitle = Styled.h2`
  font-size: 30px;
  font-weight: 700;
  text-align: center;
  margin: 30px 0px 0px 0px;
`;

const StyledSubTitle = Styled.div`
  font-size: 20px;
  font-weight: 600;
  text-align: center;
  margin: 20px 0px;
`;

const StyledButton = Styled.div`
  background-color: #008800;
  padding: 10px 30px;
  color: #ffffff;
  border-radius: 30px;
  cursor: pointer;
  font-size: 20px;
  transition: all 0.5s;

  &:hover {
    box-shadow: 5px 5px 5px #aaaaaa;
    padding: 15px 40px;
    font-size: 30px;
  }
`;

const ProjectComponent = (props) => {
  useEffect(() => {
    DoScroll();
  }, []);

  return (
    <div style={{display: 'flex', flexDirection: 'column', alignItems: 'center', minHeight: '600px'}}>
      <div style={{padding: '40px 0px', fontSize: '32px', fontWeight: 'bold'}}>Demo Projects</div>

      <Section style={{backgroundColor: props.theme.home.background2, color: props.theme.home.color}}> 
        <StyledContainer>
          <StyledLeft>
            <StyledTitle>
              WellFlag Web 3D
            </StyledTitle>
            <StyledSubTitle>
              An online 3D visualization application for geophysicists and geologists
            </StyledSubTitle>
            <div style={{paddingLeft: '20px'}}>
              <ul style={{lineHeight:'180%', fontSize: '18px'}}>
                <li>High performance 3D rendering with easy navigation</li>
                <li>Create project in the cloud and manage online</li>
                <li>Build project online with context menu</li>
                <li>MicroSeismic events animation with fracture data</li>
              </ul> 
            </div>

            <div style={{display: 'flex', justifyContent: 'center', paddingTop: '10px'}}>
                <StyledButton onClick={() => window.open("http://reactwebgl.somee.com/")}>
                  <span>Visit the website</span>
                </StyledButton>
              </div>
          </StyledLeft>
          <StyledRight>
            <img src={WellflagPhoto} style={{width: '100%', height: 'auto'}} alt="" />
          </StyledRight>
        </StyledContainer>

      </Section>

      <Section style={{backgroundColor: props.theme.home.background1, color: props.theme.home.color}}> 
      <StyledContainer reverse={true}>
          <StyledLeft>
          <img src={StockHubPhoto} style={{width: '100%', height: 'auto'}} alt="" />
          </StyledLeft>
          <StyledRight>
              <StyledTitle>
                StockHub
              </StyledTitle>
              <StyledSubTitle>
                Help you make the best decision in your investment
              </StyledSubTitle>
              <div style={{paddingLeft: '40px'}}>
                <ul style={{lineHeight:'180%', fontSize: '18px'}}>
                  <li>Lists all stocks in 10 US exchange centers</li>
                  <li>Provides data in sortable table to help you quickly find your stock</li>
                  <li>Links to many other stock websites to help you find more infomation</li>
                  <li>Save your selections in groups for later analysis</li>
                </ul> 
              </div>

              <div style={{display: 'flex', justifyContent: 'center'}}>
                <StyledButton onClick={() => window.open("http://stockhub.somee.com")}>
                  <span>Visit the website</span>
                </StyledButton>
              </div>
          </StyledRight>
        </StyledContainer>

      </Section>      
    </div>
  )
}

export default ProjectComponent;