import React from "react";
import HomeComponent from '../home/index';
import ExperienceComponent from '../experience/index';
import ResumeComponent from '../resume/index';
import SignInComponent from '../auth/signin';
import ForgetPasswordComponent from '../auth/forgetpassword';
import ResetPasswordComponent from '../auth/resetpassword';
import SignUpComponent from '../auth/signup';
import { withTheme } from 'styled-components';
import EducationComponent from '../education/index';
import ProjectComponent from '../project/index';

const ContentTemplate = (props) => {
  const getParas = () => {
    let dict = {};
    let params = props.location.search.slice(1, props.location.search.length).split('&');
    params.forEach(element => {
      let items = element.split('=');
      if (items.length === 2) {
        dict[items[0]] = items[1];
      }
    });
    return dict;
  }

  const paras = getParas();
  
  const templates = {
      home: HomeComponent,
      experience: ExperienceComponent,
      education: EducationComponent,
      resume: ResumeComponent,
      project: ProjectComponent,
      login: SignInComponent,
      forgetpassword: ForgetPasswordComponent,
      resetpassword: ResetPasswordComponent,
      signup: SignUpComponent,
  };  

  const Template = templates[paras['c'] ?? ''] || templates.home;

  return (
    <Template {...props} />
  )
}

export default withTheme(ContentTemplate);